class Solution:
    def findReplaceString(self, s: str, indices: List[int], sources: List[str], targets: List[str]) -> str:
        ops = sorted(zip(indices, sources, targets), key=lambda x: -x[0])
        s = list(s)
        for i, src, tgt in ops:
            if s[i:i+len(src)] == list(src):
                s[i:i+len(src)] = list(tgt)
        return ''.join(s)

solution_js:
var findReplaceString = function(s, indices, sources, targets) {
    const ops = indices.map((idx, i) => [idx, sources[i], targets[i]])
        .sort((a, b) => b[0] - a[0]);
    let arr = s.split('');
    for (const [i, src, tgt] of ops) {
        if (arr.slice(i, i + src.length).join('') === src) {
            arr.splice(i, src.length, ...tgt.split(''));
        }
    }
    return arr.join('');
};

var canChange = function(start, target) {
    const n = start.length;
    let i = 0, j = 0;
    while (i <= n && j <= n) {
        while (i < n && start[i] === '_') i++;
        while (j < n && target[j] === '_') j++;
        if (i === n && j === n) return true;
        if (i === n || j === n) return false;
        if (start[i] !== target[j]) return false;
        if (start[i] === 'L' && i < j) return false;
        if (start[i] === 'R' && i > j) return false;
        i++; j++;
    }
    return true;
};

