from collections import Counter
class Solution:
    def isTrionic(self, nums: List[int]) -> bool:
        freq = Counter(nums)
        if any(v % 3 != 0 for v in freq.values()):
            return False
        nums.sort()
        for i in range(0, len(nums), 3):
            if nums[i] != nums[i+1] or nums[i+1] != nums[i+2]:
                return False
        return True

solution_js:
var isTrionic = function(nums) {
    const freq = new Map();
    for (const n of nums) freq.set(n, (freq.get(n) || 0) + 1);
    for (const v of freq.values()) if (v % 3 !== 0) return false;
    nums.sort((a, b) => a - b);
    for (let i = 0; i < nums.length; i += 3) {
        if (nums[i] !== nums[i+1] || nums[i+1] !== nums[i+2]) return false;
    }
    return true;
};

var hasGroupsSizeX = function(deck) {
    const freq = new Map();
    for (const c of deck) freq.set(c, (freq.get(c) || 0) + 1);
    function gcd(a, b) { return b === 0 ? a : gcd(b, a % b); }
    let g = 0;
    for (const v of freq.values()) g = gcd(g, v);
    return g >= 2;
};

